CREATE TABLE `fx_approval_log` (
  `log_id` bigint NOT NULL AUTO_INCREMENT COMMENT '日志ID',
  `trade_id` varchar(50) NOT NULL COMMENT '交易ID',
  `approval_node` varchar(20) DEFAULT NULL COMMENT '审批节点：MAKE/CHECK/AUTHORIZE',
  `approver_id` bigint DEFAULT NULL COMMENT '审批人ID',
  `approver_name` varchar(50) DEFAULT NULL COMMENT '审批人姓名',
  `approver_org` varchar(20) DEFAULT NULL COMMENT '审批人机构',
  `decision` varchar(20) DEFAULT NULL COMMENT '决定：APPROVE/REJECT/RETURN',
  `decision_time` datetime DEFAULT NULL COMMENT '决定时间',
  `comment` varchar(500) DEFAULT NULL COMMENT '审批意见',
  `before_status` varchar(30) DEFAULT NULL COMMENT '变更前状态',
  `after_status` varchar(30) DEFAULT NULL COMMENT '变更后状态',
  PRIMARY KEY (`log_id`),
  KEY `idx_trade_id` (`trade_id`)
) ENGINE=InnoDB AUTO_INCREMENT=1708 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='审批日志表';
