DROP TABLE IF EXISTS `fx_credit_limit`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `fx_credit_limit` (
  `limit_id` bigint NOT NULL AUTO_INCREMENT COMMENT '额度ID',
  `customer_id` varchar(50) NOT NULL COMMENT '客户ID',
  `currency` varchar(10) NOT NULL COMMENT '币种',
  `credit_limit_amount` decimal(20,2) DEFAULT NULL COMMENT '授信额度',
  `used_amount` decimal(20,2) DEFAULT '0.00' COMMENT '已用额度',
  `available_amount` decimal(20,2) DEFAULT NULL COMMENT '可用额度',
  `status` varchar(2) DEFAULT '1' COMMENT '状态：1启用 0停用',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`limit_id`),
  KEY `idx_customer_currency` (`customer_id`,`currency`)
) ENGINE=InnoDB AUTO_INCREMENT=11 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='客户授信额度表';
