DROP TABLE IF EXISTS `fx_customer`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `fx_customer` (
  `customer_id` varchar(50) NOT NULL COMMENT '客户ID',
  `customer_name` varchar(100) NOT NULL COMMENT '客户名称',
  `customer_type` varchar(20) DEFAULT NULL COMMENT '客户类型',
  `corp_type` varchar(30) DEFAULT NULL COMMENT '企业类型（经营模式划分）：MANUFACTURING制造业/TRADING贸易业/SERVICE服务业/INVESTMENT_HOLDING投资控股/FINANCIAL_INSTITUTION金融机构/SME中小民企',
  `id_type` varchar(20) DEFAULT NULL COMMENT '证件类型',
  `id_no` varchar(50) DEFAULT NULL COMMENT '证件号码',
  `org_code` varchar(20) DEFAULT NULL COMMENT '所属机构编码',
  `credit_level` varchar(20) DEFAULT NULL COMMENT '信用等级',
  `risk_level` varchar(2) DEFAULT NULL COMMENT '风评等级：A激进型 B平衡型 C保守型',
  `status` varchar(2) DEFAULT '1' COMMENT '状态：1启用 0停用',
  `contact_person` varchar(50) DEFAULT NULL COMMENT '联系人',
  `contact_phone` varchar(30) DEFAULT NULL COMMENT '联系电话',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`customer_id`),
  KEY `idx_org_code` (`org_code`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='客户表';
