--
-- Table structure for table `fx_customer_account`
--

DROP TABLE IF EXISTS `fx_customer_account`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `fx_customer_account` (
  `account_id` bigint NOT NULL AUTO_INCREMENT COMMENT '账户ID',
  `customer_id` varchar(50) NOT NULL COMMENT '客户ID',
  `account_no` varchar(50) NOT NULL COMMENT '账号',
  `currency` varchar(10) NOT NULL COMMENT '币种',
  `account_type` varchar(10) DEFAULT NULL COMMENT '账户类型：SPOT现汇 CASH现钞',
  `balance` decimal(20,2) DEFAULT '0.00' COMMENT '账户余额',
  `cny_balance` decimal(20,2) DEFAULT '0.00' COMMENT '账户折人民币余额（按当日即期汇率折算）',
  `frozen_amount` decimal(20,2) DEFAULT '0.00' COMMENT '冻结金额',
  `status` varchar(2) DEFAULT '1' COMMENT '状态：1启用 0停用',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`account_id`),
  UNIQUE KEY `uk_account_no` (`account_no`),
  KEY `idx_customer_id` (`customer_id`)
) ENGINE=InnoDB AUTO_INCREMENT=2810 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='客户账户表';
/*!40101 SET character_set_client = @saved_cs_client */;

