--
-- Table structure for table `fx_forward_trade`
--

DROP TABLE IF EXISTS `fx_forward_trade`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `fx_forward_trade` (
  `trade_id` varchar(50) NOT NULL COMMENT '交易ID',
  `maturity_date` date DEFAULT NULL COMMENT '到期日',
  `forward_rate` decimal(18,4) DEFAULT NULL COMMENT '远期汇率',
  `forward_point` decimal(18,4) DEFAULT NULL COMMENT '远期点',
  `term` varchar(10) DEFAULT NULL COMMENT '期限：1D/SW/1M/2M/3M/6M/1Y',
  `settlement_method` varchar(10) DEFAULT NULL COMMENT '交割方式：FULL/NET',
  `net_settlement_amount` decimal(20,2) DEFAULT NULL COMMENT '差额交割金额',
  `currency1_account` varchar(50) DEFAULT NULL,
  `currency2_account` varchar(50) DEFAULT NULL,
  `margin_account_id` varchar(50) DEFAULT NULL COMMENT '保证金账户ID',
  `margin_amount` decimal(20,2) DEFAULT NULL COMMENT '保证金金额',
  `amount` decimal(20,2) DEFAULT NULL COMMENT '金额',
  `is_rolled_over` varchar(2) DEFAULT NULL COMMENT '是否展期：Y/N',
  `original_trade_id` varchar(50) DEFAULT NULL COMMENT '原交易ID',
  `early_delivery_flag` varchar(2) DEFAULT NULL COMMENT '提前交割标志：Y/N',
  `early_default_flag` varchar(2) DEFAULT NULL COMMENT '提前违约标志：Y/N',
  PRIMARY KEY (`trade_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='远期交易子表';
/*!40101 SET character_set_client = @saved_cs_client */;

