DROP TABLE IF EXISTS `fx_margin_param`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `fx_margin_param` (
  `param_id` bigint NOT NULL AUTO_INCREMENT COMMENT '参数ID',
  `param_code` varchar(50) NOT NULL COMMENT '参数编码',
  `param_name` varchar(100) DEFAULT NULL COMMENT '参数名称',
  `param_value` varchar(200) DEFAULT NULL COMMENT '参数值',
  `currency` varchar(10) DEFAULT NULL COMMENT '币种',
  `trade_type` varchar(20) DEFAULT NULL COMMENT '交易类型',
  `description` varchar(200) DEFAULT NULL COMMENT '描述',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`param_id`),
  UNIQUE KEY `uk_param_code` (`param_code`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='保证金参数表';
