CREATE TABLE `fx_option_trade` (
  `trade_id` varchar(50) NOT NULL COMMENT '交易ID',
  `option_type` varchar(10) DEFAULT NULL COMMENT '期权类型：CALL/PUT',
  `option_style` varchar(10) DEFAULT NULL COMMENT '行权方式：AMERICAN/EUROPEAN',
  `strike_price` decimal(18,8) DEFAULT NULL COMMENT '执行价',
  `premium_amount` decimal(20,2) DEFAULT NULL COMMENT '期权费金额',
  `premium_currency` varchar(10) DEFAULT NULL COMMENT '期权费币种',
  `premium_value_date` date DEFAULT NULL COMMENT '期权费起息日',
  `premium_paid_flag` varchar(2) DEFAULT NULL COMMENT '期权费是否已支付：Y/N',
  `premium_account_id` varchar(50) DEFAULT NULL COMMENT '期权费账户ID',
  `maturity_date` date DEFAULT NULL COMMENT '到期日',
  `exercise_date` date DEFAULT NULL COMMENT '行权日',
  `exercise_flag` varchar(2) DEFAULT NULL COMMENT '是否行权标志：Y/N',
  `abandon_flag` varchar(2) DEFAULT NULL COMMENT '是否放弃标志：Y/N',
  `abandon_date` date DEFAULT NULL COMMENT '放弃日（审批通过日期）',
  `settlement_method` varchar(10) DEFAULT NULL COMMENT '交割方式：FULL/NET',
  `buyer_seller` varchar(10) DEFAULT NULL COMMENT '买卖方向',
  `currency1_account` varchar(50) DEFAULT NULL COMMENT '货币1账户',
  `currency2_account` varchar(50) DEFAULT NULL COMMENT '货币2账户',
  `notional_amount` decimal(20,2) DEFAULT NULL COMMENT '名义金额',
  `observation_start_date` date DEFAULT NULL COMMENT '观察开始日',
  `observation_end_date` date DEFAULT NULL COMMENT '观察结束日',
  `exercise_time_point` datetime DEFAULT NULL COMMENT '行权时间点',
  `days` int DEFAULT NULL COMMENT '天数',
  `auto_exercise_flag` varchar(2) DEFAULT NULL COMMENT '是否自动行权：Y/N',
  `close_date` date DEFAULT NULL COMMENT '平仓日',
  `close_premium` decimal(20,2) DEFAULT NULL COMMENT '平仓期权费',
  `close_pnl` decimal(20,2) DEFAULT NULL COMMENT '平仓盈亏',
  `closed_amount` decimal(20,2) DEFAULT NULL COMMENT '已平仓金额',
  `remaining_amount` decimal(20,2) DEFAULT NULL COMMENT '剩余金额',
  `reference_rate` decimal(18,8) DEFAULT NULL COMMENT '参考汇率',
  PRIMARY KEY (`trade_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='期权交易子表';
