--
-- Table structure for table `fx_quote`
--

DROP TABLE IF EXISTS `fx_quote`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `fx_quote` (
  `quote_id` bigint NOT NULL AUTO_INCREMENT COMMENT '报价ID',
  `quote_type` varchar(20) NOT NULL COMMENT '报价类型：SPOT/FORWARD/SWAP',
  `currency_pair` varchar(20) NOT NULL COMMENT '货币对',
  `base_currency` varchar(10) NOT NULL COMMENT '基础货币',
  `quote_currency` varchar(10) NOT NULL COMMENT '报价货币',
  `term` varchar(20) DEFAULT NULL COMMENT '期限（远期/掉期如 1M/3M）',
  `maturity_date` date DEFAULT NULL COMMENT '到期日',
  `market_mid_rate` decimal(18,4) DEFAULT NULL COMMENT '市场中间价',
  `total_buy_rate` decimal(18,4) DEFAULT NULL COMMENT '总行买入价',
  `total_sell_rate` decimal(18,4) DEFAULT NULL COMMENT '总行卖出价',
  `branch_customer_buy_rate` decimal(18,4) DEFAULT NULL COMMENT '分/客买价',
  `branch_customer_sell_rate` decimal(18,4) DEFAULT NULL COMMENT '分/客卖价',
  `forward_point` decimal(18,4) DEFAULT NULL COMMENT '远期点',
  `swap_point` decimal(18,4) DEFAULT NULL COMMENT '掉期点',
  `status` varchar(20) DEFAULT 'ACTIVE' COMMENT '状态',
  `effective_time` datetime DEFAULT NULL COMMENT '生效时间',
  `published_by` bigint DEFAULT NULL COMMENT '发布人',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`quote_id`),
  KEY `idx_quote_type_pair` (`quote_type`,`currency_pair`),
  KEY `idx_currency_pair` (`currency_pair`)
) ENGINE=InnoDB AUTO_INCREMENT=16481 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='报价表';
/*!40101 SET character_set_client = @saved_cs_client */;

