--
-- Table structure for table `fx_spot_trade`
--

DROP TABLE IF EXISTS `fx_spot_trade`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `fx_spot_trade` (
  `trade_id` varchar(50) NOT NULL COMMENT '交易ID',
  `settlement_type` varchar(10) DEFAULT NULL COMMENT '交割类型：T0/T1/T2',
  `spot_rate` decimal(18,4) DEFAULT NULL COMMENT '即期汇率',
  `customer_rate` decimal(18,4) DEFAULT NULL COMMENT '客户汇率',
  `cost_rate` decimal(18,4) DEFAULT NULL COMMENT '成本汇率',
  `currency1_account` varchar(50) DEFAULT NULL COMMENT '货币1账户',
  `currency2_account` varchar(50) DEFAULT NULL COMMENT '货币2账户',
  `margin_account_id` varchar(50) DEFAULT NULL COMMENT '保证金账户ID',
  `margin_amount` decimal(20,2) DEFAULT NULL COMMENT '保证金金额',
  `amount` decimal(20,2) DEFAULT NULL COMMENT '金额',
  PRIMARY KEY (`trade_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='即期交易子表';
/*!40101 SET character_set_client = @saved_cs_client */;

