--
-- Table structure for table `fx_swap_trade`
--

DROP TABLE IF EXISTS `fx_swap_trade`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `fx_swap_trade` (
  `trade_id` varchar(50) NOT NULL COMMENT '交易ID',
  `swap_type` varchar(10) DEFAULT NULL COMMENT '掉期类型：S_B近卖远买/B_S近买远卖',
  `near_leg_direction` varchar(10) DEFAULT NULL COMMENT '近端方向',
  `near_leg_amount` decimal(20,2) DEFAULT NULL COMMENT '近端金额',
  `near_leg_rate` decimal(18,4) DEFAULT NULL COMMENT '近端汇率',
  `near_leg_value_date` date DEFAULT NULL COMMENT '近端起息日',
  `near_leg_account` varchar(50) DEFAULT NULL COMMENT '近端账户',
  `far_leg_direction` varchar(10) DEFAULT NULL COMMENT '远端方向',
  `far_leg_amount` decimal(20,2) DEFAULT NULL COMMENT '远端金额',
  `far_leg_rate` decimal(18,4) DEFAULT NULL COMMENT '远端汇率',
  `far_leg_value_date` date DEFAULT NULL COMMENT '远端起息日',
  `far_leg_account` varchar(50) DEFAULT NULL COMMENT '远端账户',
  `swap_point` decimal(18,4) DEFAULT NULL COMMENT '掉期点',
  `near_spot_rate` decimal(18,4) DEFAULT NULL COMMENT '近端即期汇率',
  `is_pure_swap` varchar(2) DEFAULT NULL COMMENT '是否纯掉期：Y/N',
  `margin_account_id` varchar(50) DEFAULT NULL COMMENT '保证金账户ID',
  `margin_amount` decimal(20,2) DEFAULT NULL COMMENT '保证金金额',
  `near_leg_cost_rate` decimal(18,4) DEFAULT NULL COMMENT '近端成本汇率',
  `near_leg_branch_profit_point` decimal(18,2) DEFAULT NULL COMMENT '近端分行收益点',
  `far_leg_cost_rate` decimal(18,4) DEFAULT NULL COMMENT '远端成本汇率',
  `far_leg_branch_profit_point` decimal(18,2) DEFAULT NULL COMMENT '远端分行收益点',
  `near_leg_customer_rate` decimal(18,4) DEFAULT NULL COMMENT '近端客户汇率',
  `far_leg_customer_rate` decimal(18,4) DEFAULT NULL COMMENT '远端客户汇率',
  `near_leg_currency1_account` varchar(50) DEFAULT NULL COMMENT '??????1???',
  `near_leg_currency2_account` varchar(50) DEFAULT NULL COMMENT '??????2???',
  `far_leg_currency1_account` varchar(50) DEFAULT NULL COMMENT '??????1???',
  `far_leg_currency2_account` varchar(50) DEFAULT NULL COMMENT '??????2???',
  `near_leg_settlement_method` varchar(10) DEFAULT NULL COMMENT '???????????ULL/NET',
  `far_leg_settlement_method` varchar(10) DEFAULT NULL COMMENT '???????????ULL/NET',
  `term` varchar(10) DEFAULT NULL COMMENT '????????N/TN/SN/SW/1M',
  PRIMARY KEY (`trade_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='掉期交易子表';
/*!40101 SET character_set_client = @saved_cs_client */;

