--
-- Table structure for table `fx_task`
--

DROP TABLE IF EXISTS `fx_task`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `fx_task` (
  `task_id` bigint NOT NULL AUTO_INCREMENT COMMENT '任务ID',
  `task_type` varchar(30) DEFAULT NULL COMMENT '任务类型',
  `trade_id` varchar(50) DEFAULT NULL COMMENT '交易ID',
  `business_key` varchar(50) DEFAULT NULL COMMENT '业务键',
  `business_type` varchar(30) DEFAULT NULL COMMENT '业务类型',
  `priority` int DEFAULT '0' COMMENT '优先级',
  `assignee_id` bigint DEFAULT NULL COMMENT '指派人ID',
  `assignee_role` varchar(50) DEFAULT NULL COMMENT '指派角色',
  `assignee_org` varchar(20) DEFAULT NULL COMMENT '指派机构',
  `assignee_org_level` int DEFAULT NULL COMMENT '指派机构层级',
  `status` varchar(20) DEFAULT 'PENDING' COMMENT '状态：PENDING/CLAIMED/DONE/CANCELLED/TIMEOUT',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `due_time` datetime DEFAULT NULL COMMENT '到期时间',
  `claim_time` datetime DEFAULT NULL COMMENT '认领时间',
  `complete_time` datetime DEFAULT NULL COMMENT '完成时间',
  `claim_lock` varchar(100) DEFAULT NULL COMMENT '认领锁',
  `payload` text COMMENT '任务载荷（JSON）',
  PRIMARY KEY (`task_id`),
  KEY `idx_status` (`status`),
  KEY `idx_assignee_id` (`assignee_id`),
  KEY `idx_trade_id` (`trade_id`),
  KEY `idx_business_key` (`business_key`)
) ENGINE=InnoDB AUTO_INCREMENT=115 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='任务表';
/*!40101 SET character_set_client = @saved_cs_client */;

