--
-- Table structure for table `fx_trade_lifecycle`
--

DROP TABLE IF EXISTS `fx_trade_lifecycle`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `fx_trade_lifecycle` (
  `event_id` bigint NOT NULL AUTO_INCREMENT COMMENT '事件ID',
  `trade_id` varchar(50) NOT NULL COMMENT '交易ID',
  `event_type` varchar(30) DEFAULT NULL COMMENT '事件类型',
  `event_time` datetime DEFAULT NULL COMMENT '事件时间',
  `operator_id` bigint DEFAULT NULL COMMENT '操作人ID',
  `before_status` varchar(30) DEFAULT NULL COMMENT '变更前状态',
  `after_status` varchar(30) DEFAULT NULL COMMENT '变更后状态',
  `event_amount` decimal(20,2) DEFAULT NULL COMMENT '事件金额',
  `event_rate` decimal(18,8) DEFAULT NULL COMMENT '事件汇率',
  `related_trade_id` varchar(50) DEFAULT NULL COMMENT '关联交易ID',
  `remark` varchar(500) DEFAULT NULL COMMENT '备注',
  `audit_snapshot` text COMMENT '审计快照',
  PRIMARY KEY (`event_id`),
  KEY `idx_trade_id` (`trade_id`),
  KEY `idx_event_type` (`event_type`)
) ENGINE=InnoDB AUTO_INCREMENT=647 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='交易生命周期事件表';
/*!40101 SET character_set_client = @saved_cs_client */;

