--
-- Table structure for table `fx_trade_master`
--

DROP TABLE IF EXISTS `fx_trade_master`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `fx_trade_master` (
  `trade_id` varchar(50) NOT NULL COMMENT '交易ID',
  `business_no` varchar(50) NOT NULL COMMENT '业务编号',
  `trade_type` varchar(20) NOT NULL COMMENT '交易类型：SPOT/FORWARD/SWAP/OPTION',
  `status` varchar(30) NOT NULL COMMENT '交易状态',
  `branch_code` varchar(20) DEFAULT NULL COMMENT '分行编码',
  `customer_id` varchar(50) DEFAULT NULL COMMENT '客户ID',
  `customer_name` varchar(100) DEFAULT NULL COMMENT '客户名称',
  `base_currency` varchar(10) DEFAULT NULL COMMENT '基础货币',
  `quote_currency` varchar(10) DEFAULT NULL COMMENT '报价货币',
  `currency_pair` varchar(20) DEFAULT NULL COMMENT '货币对',
  `notional_amount` decimal(20,2) DEFAULT NULL COMMENT '名义金额',
  `counter_amount` decimal(20,2) DEFAULT NULL COMMENT '对手金额',
  `trade_direction` varchar(10) DEFAULT NULL COMMENT '交易方向：BUY/SELL',
  `value_date` date DEFAULT NULL COMMENT '起息日',
  `trade_date` date DEFAULT NULL COMMENT '交易日',
  `maturity_date` date DEFAULT NULL COMMENT '到期日',
  `delivery_type` varchar(10) DEFAULT NULL COMMENT '交割类型：T0/T1/T2',
  `settlement_method` varchar(10) DEFAULT NULL COMMENT '交割方式：FULL/NET',
  `spot_rate` decimal(18,4) DEFAULT NULL COMMENT '即期汇率',
  `customer_rate` decimal(18,4) DEFAULT NULL COMMENT '客户汇率',
  `cost_rate` decimal(18,4) DEFAULT NULL COMMENT '成本汇率',
  `branch_profit_point` decimal(18,2) DEFAULT NULL COMMENT '分行利润点',
  `special_trade_type` varchar(30) DEFAULT NULL COMMENT '特殊交易类型',
  `original_trade_id` varchar(50) DEFAULT NULL COMMENT '原交易ID',
  `related_trade_id` varchar(50) DEFAULT NULL COMMENT '关联交易ID',
  `maker_id` bigint DEFAULT NULL COMMENT '经办人ID',
  `checker_id` bigint DEFAULT NULL COMMENT '复核人ID',
  `authorizer_id` bigint DEFAULT NULL COMMENT '授权人ID',
  `make_time` datetime DEFAULT NULL COMMENT '经办时间',
  `check_time` datetime DEFAULT NULL COMMENT '复核时间',
  `authorize_time` datetime DEFAULT NULL COMMENT '授权时间',
  `purpose_code` varchar(50) DEFAULT NULL COMMENT '用途编码',
  `fx_purpose_code` varchar(50) DEFAULT NULL COMMENT '外汇用途编码',
  `rcpmis_report_flag` varchar(2) DEFAULT NULL COMMENT 'RCPMIS上报标志',
  `rcpmis_report_time` datetime DEFAULT NULL COMMENT 'RCPMIS上报时间',
  `version` int DEFAULT '0' COMMENT '版本号',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `original_trade_type` varchar(30) DEFAULT NULL COMMENT '原交易类型',
  `netting_currency` varchar(10) DEFAULT NULL COMMENT '轧差货币',
  `netting_account` varchar(50) DEFAULT NULL COMMENT '轧差账户',
  `netting_amount` decimal(20,2) DEFAULT NULL COMMENT '轧差金额',
  PRIMARY KEY (`trade_id`),
  UNIQUE KEY `uk_business_no` (`business_no`),
  KEY `idx_trade_type` (`trade_type`),
  KEY `idx_status` (`status`),
  KEY `idx_customer_id` (`customer_id`),
  KEY `idx_branch_code` (`branch_code`),
  KEY `idx_original_trade_id` (`original_trade_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='交易主表';
/*!40101 SET character_set_client = @saved_cs_client */;

